import{_ as t,o as s,c as l,ak as e}from"./chunks/framework.CzRcPwtJ.js";const m=JSON.parse('{"title":"战斗机制总览","description":"","frontmatter":{"title":"战斗机制总览"},"headers":[],"relativePath":"battle-system.md","filePath":"battle-system.md","lastUpdated":1784443077000}'),i={name:"battle-system.md"};function r(n,a,o,c,d,p){return s(),l("div",null,[...a[0]||(a[0]=[e('<h1 id="战斗机制总览" tabindex="-1">战斗机制总览 <a class="header-anchor" href="#战斗机制总览" aria-label="Permalink to &quot;战斗机制总览&quot;">​</a></h1><blockquote><p>忘却前夜的战斗是<strong>指令卡 Roguelite</strong>：每位唤醒体自带一套卡组，玩家用算力打出指令卡，靠界域体系、狂气爆发与命轮滚雪球。 本页为系统说明（机制层），具体到每位角色「怎么玩」见<a href="/brain-in-a-vat/wiki/playstyle.html">玩法图鉴</a>。社区译名为准，数值随版本浮动。</p></blockquote><nav class="table-of-contents"><ul><li><a href="#队伍与卡组">队伍与卡组</a></li><li><a href="#算力-arithmetica">算力（Arithmetica）</a></li><li><a href="#狂气与爆发">狂气与爆发</a></li><li><a href="#四界域">四界域</a></li><li><a href="#命轮-神器">命轮（神器）</a></li><li><a href="#稀有度">稀有度</a></li><li><a href="#延伸">延伸</a></li></ul></nav><h2 id="队伍与卡组" tabindex="-1">队伍与卡组 <a class="header-anchor" href="#队伍与卡组" aria-label="Permalink to &quot;队伍与卡组&quot;">​</a></h2><ul><li>一支队伍编入数名唤醒体；每位唤醒体携带自己的<strong>指令卡</strong>与一张<strong>灵知觉醒</strong>卡。</li><li>每位唤醒体的卡牌大致分三类：</li></ul><p><span class="card-type-badge card-command">指令卡</span> 角色的常规招式，构成卡组主体，靠算力打出。<br><span class="card-type-badge card-spirit">灵知觉醒</span> 角色的觉醒/核心卡，往往是流派引擎（过牌、滚雪球、形态切换）。<br><span class="card-type-badge card-madness">狂气爆发</span> 狂气满后释放的大招，不耗算力。 </p><div class="tip custom-block"><p class="custom-block-title">小学生比喻</p><p>指令卡 = 平时的普通攻击牌；灵知觉醒 = 角色的「必杀引擎」；狂气爆发 = 攒满怒气槽后免费放的大招。</p></div><h2 id="算力-arithmetica" tabindex="-1">算力（Arithmetica） <a class="header-anchor" href="#算力-arithmetica" aria-label="Permalink to &quot;算力（Arithmetica）&quot;">​</a></h2><ul><li>每回合开局获得固定算力（基础 <strong>5 点</strong>），打指令卡消耗算力。</li><li>算力是每回合的「行动力预算」，部分角色/命轮能回算力或降卡费，从而一回合打出更多牌。</li></ul><p><span class="arithmetica-cost">⚙ 5</span> = 每回合初始算力</p><div class="tip custom-block"><p class="custom-block-title">小学生比喻</p><p>算力 = 每回合的零花钱，每张牌标价多少就花多少，花光这回合就不能再出牌了。</p></div><h2 id="狂气与爆发" tabindex="-1">狂气与爆发 <a class="header-anchor" href="#狂气与爆发" aria-label="Permalink to &quot;狂气与爆发&quot;">​</a></h2><ul><li>角色通过出牌、受击等积累<strong>狂气</strong>（上限 100）。</li><li>狂气满 100 即可释放<strong>狂气爆发</strong>（不耗算力的大招）。</li><li>多数角色可二次叠满触发<strong>超限爆发</strong>，把狂气上限从 100 提到 200，爆发更强。</li></ul><div class="madness-bar"></div><p><span class="card-type-badge card-madness">狂气 100</span> → 狂气爆发　|　再叠满 → <span class="card-type-badge card-madness">超限 200</span> → 超限爆发</p><div class="tip custom-block"><p class="custom-block-title">小学生比喻</p><p>狂气槽 = 怒气条，满了放大招；超限 = 把怒气条上限撑大一倍，憋出更猛的大招。</p></div><h2 id="四界域" tabindex="-1">四界域 <a class="header-anchor" href="#四界域" aria-label="Permalink to &quot;四界域&quot;">​</a></h2><p>唤醒体按<strong>界域</strong>划分玩法体系，决定核心机制与配队方向。混沌可与任意界域混编。</p><table tabindex="0"><thead><tr><th>界域</th><th>体系关键词</th></tr></thead><tbody><tr><td><span class="realm-badge realm-chaos">混沌</span></td><td>可与任意界域混编 · 反击 / 打击 / 过牌 / 刷牌</td></tr><tr><td><span class="realm-badge realm-aequor">深海</span></td><td>触腕体系 · 深渊号令 · 触腕齐射</td></tr><tr><td><span class="realm-badge realm-caro">血肉</span></td><td>日服译「狂魔」· 胚胎 / 中毒 / 卖血 / 斩杀</td></tr><tr><td><span class="realm-badge realm-ultra">超维</span></td><td>超维空间 · 额外回合 · 斩杀 / 暴击</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">小学生比喻</p><p>界域 = 角色的「门派」，决定他练什么武功路子；混沌是「百搭门派」，能跟谁都组队。</p></div><h2 id="命轮-神器" tabindex="-1">命轮（神器） <a class="header-anchor" href="#命轮-神器" aria-label="Permalink to &quot;命轮（神器）&quot;">​</a></h2><ul><li><strong>命轮</strong>是可装备的局外/局内强化遗物，给角色叠增益、改流派。</li><li>每位角色可装备数枚命轮（含高稀有度的核心命轮），叠位影响强度。</li><li>具名命轮常带叙事典故，资料见<a href="/brain-in-a-vat/wiki/item-stories.html">道具故事</a>。</li></ul><div class="tip custom-block"><p class="custom-block-title">小学生比喻</p><p>命轮 = 给角色戴的装备/法宝，戴对了能把他的特长放大好几倍。</p></div><h2 id="稀有度" tabindex="-1">稀有度 <a class="header-anchor" href="#稀有度" aria-label="Permalink to &quot;稀有度&quot;">​</a></h2><p><span class="rarity-ssr">SSR</span> · <span class="rarity-sr">SR</span> · <span class="rarity-r">R</span> —— 卡池概率与保底见[唤醒系统](/summon)。 </p><h2 id="延伸" tabindex="-1">延伸 <a class="header-anchor" href="#延伸" aria-label="Permalink to &quot;延伸&quot;">​</a></h2><ul><li><a href="/brain-in-a-vat/wiki/playstyle.html">玩法图鉴</a>：每位唤醒体的核心循环 / 招牌技能 / 配队</li><li><a href="/brain-in-a-vat/wiki/characters.html">唤醒体图鉴</a>：58 位可玩角色按界域分组 + 详情页</li><li><a href="/brain-in-a-vat/wiki/summon.html">唤醒系统</a>：366 卡池概率 / 保底</li></ul>',27)])])}const b=t(i,[["render",r]]);export{m as __pageData,b as default};
